// Snapshot context + compute yesterday window as epoch ms (LinkedIn uses ms, not seconds)
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];
const startMs = new Date(dateStr + 'T00:00:00Z').getTime();
const endMs   = new Date(dateStr + 'T23:59:59Z').getTime();

return $input.all().map(item => ({
  json: {
    channel_id:   item.json.channel_id,
    account_id:   item.json.account_id,
    access_token: item.json.access_token,
    platform:     'linkedin',
    metric_date:  dateStr,
    start_ms:     startMs,
    end_ms:       endMs
  }
}));

// organizationalEntityShareStatistics response shape:
// { elements: [{ timeRange: {...}, totalShareStatistics: { impressionCount, clickCount, likeCount, commentCount, shareCount, uniqueImpressionsCount } }] }
const apiItems = $input.all();
const channelItems = $('Init - Channel State').all();

return apiItems.map((apiItem, idx) => {
  const channel = channelItems[idx]?.json || {};
  const elements = apiItem.json.elements || [];

  // Sum across all time buckets returned (should be 1 for a single-day window)
  const totals = elements.reduce((acc, el) => {
    const s = el.totalShareStatistics || {};
    acc.impressions += (s.impressionCount        || 0);
    acc.reach       += (s.uniqueImpressionsCount || 0);
    acc.clicks      += (s.clickCount             || 0);
    acc.likes       += (s.likeCount              || 0);
    acc.comments    += (s.commentCount           || 0);
    acc.shares      += (s.shareCount             || 0);
    return acc;
  }, { impressions: 0, reach: 0, clicks: 0, likes: 0, comments: 0, shares: 0 });

  const engagement = totals.likes + totals.comments + totals.shares + totals.clicks;

  return {
    json: {
      channel_id:         channel.channel_id,
      platform:           'linkedin',
      metric_date:        channel.metric_date,
      reach:              parseInt(totals.reach),
      impressions:        parseInt(totals.impressions),
      engagements:        parseInt(engagement),
      clicks:             parseInt(totals.clicks),
      likes:              parseInt(totals.likes),
      comments:           parseInt(totals.comments),
      shares:             parseInt(totals.shares),
      saves:              0,
      video_views:        0,
      watch_time_seconds: 0,
      profile_visits:     0,
      follower_count:     0,
      created_at:         new Date().toISOString()
    }
  };
});
